import{_ as e,c as a,o as d,ae as l}from"./chunks/framework.Dh1jimFm.js";const u=JSON.parse('{"title":"说明文档","description":"","frontmatter":{},"headers":[],"relativePath":"doc/documentlon.md","filePath":"doc/documentlon.md"}'),o={name:"doc/documentlon.md"};function n(i,t,c,s,r,p){return d(),a("div",null,t[0]||(t[0]=[l(`<h1 id="说明文档" tabindex="-1">说明文档 <a class="header-anchor" href="#说明文档" aria-label="Permalink to &quot;说明文档&quot;">​</a></h1><h2 id="使用的注意事项" tabindex="-1">使用的注意事项 <a class="header-anchor" href="#使用的注意事项" aria-label="Permalink to &quot;使用的注意事项&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><ul><li>更新到v0.5.0请按照更新指南进行更新</li><li>更新到v0.3.0之后需要手动更改谱面后缀成<code>d3</code></li></ul></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><ul><li><p><code>offset</code>的单位为<code>ms</code></p></li><li><p><code>bpm(每分钟节拍数)</code>的<code>beat（节拍）</code>从左到右 分别是 节拍的整数部分 分数的分子部分 分母部分</p></li><li><p><code>x</code> <code>w</code>的范围为<code>0-100</code>(默认偏好下)</p></li><li><p>谱面会保存到<code>users</code>文件夹内(v0.5.0以下版本在<code>love2d</code>的文件夹内 点击按钮<code>目录</code>打开)</p></li></ul></div><hr><h2 id="使用教程" tabindex="-1">使用教程 <a class="header-anchor" href="#使用教程" aria-label="Permalink to &quot;使用教程&quot;">​</a></h2><h2 id="选择界面" tabindex="-1">选择界面 <a class="header-anchor" href="#选择界面" aria-label="Permalink to &quot;选择界面&quot;">​</a></h2><h3 id="导入" tabindex="-1">导入 <a class="header-anchor" href="#导入" aria-label="Permalink to &quot;导入&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件类型</th><th>方式</th><th>注意事项</th></tr></thead><tbody><tr><td>歌曲</td><td>拖入dakumi_editor的窗口中</td><td>后缀应为<code>wav</code>;<code>mp3</code>;<code>ogg</code>且后缀必须正确</td></tr><tr><td>谱面</td><td>选择到该谱面的歌曲然后拖入窗口</td><td>可以导入<code>.mc</code>的<code>slide</code>或<code>key</code>谱面</td></tr><tr><td>曲绘</td><td>选择到该谱面的歌曲然后拖入窗口</td><td>后缀应为<code>jpg</code>;<code>jpeg</code>;<code>png</code>且后缀必须正确 不然 <strong>dakumi_editor会报错</strong></td></tr></tbody></table><h2 id="编辑界面" tabindex="-1">编辑界面 <a class="header-anchor" href="#编辑界面" aria-label="Permalink to &quot;编辑界面&quot;">​</a></h2><p>编辑界面中细分了几个区域 分别是<code>工具栏</code> <code>侧边栏</code> <code>play</code> <code>edit</code></p><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><p>工具栏位于编辑界面上方 包含了一些常用的功能</p><table tabindex="0"><thead><tr><th>按钮</th><th>功能</th><th>对应的快捷键</th></tr></thead><tbody><tr><td>play/pause</td><td>播放当前谱面/停止播放</td><td>空格键</td></tr><tr><td>save</td><td>保存</td><td>ctrl+s</td></tr><tr><td>denom</td><td>改变节拍细分</td><td><code>up</code>/<code>down</code></td></tr><tr><td>track</td><td>改变当前轨道</td><td><code>right</code>/<code>left</code></td></tr><tr><td>scale</td><td>改变当前轨道缩放</td><td>无</td></tr><tr><td>fence</td><td>改变当前play区域栅栏数</td><td>无</td></tr><tr><td>music_speed</td><td>改变当前播放速度</td><td>无</td></tr><tr><td>note_fake</td><td>改变放置note后note的默认真假</td><td>无</td></tr><tr><td>note_head</td><td>改变放置hold后默认带note头</td><td>无</td></tr><tr><td>wipe_head</td><td>改变放置hold后默认带wipe头</td><td>无</td></tr></tbody></table><h3 id="edit区域" tabindex="-1">edit区域 <a class="header-anchor" href="#edit区域" aria-label="Permalink to &quot;edit区域&quot;">​</a></h3><p>edit区域位于play区域的右方侧边栏的左方 没有任何按钮</p><ul><li>从左到右的三个轨道分别是<code>note</code>轨道 <code>x</code>轨道 <code>w</code>轨道 以下称为第一 二 三 轨道</li><li>以下称事件为<code>event</code></li></ul><table tabindex="0"><thead><tr><th>操作</th><th>方法</th><th>注意事项</th></tr></thead><tbody><tr><td>放置note/wipe/hold</td><td>鼠标指针停留在一轨上按下<code>q</code>/<code>w</code>/<code>e</code>键 放置<code>hold</code>尾部时需要再次按下<code>e</code></td><td>无法重叠放置 且hold尾部beat应该大于hold头部beat</td></tr><tr><td>放置event</td><td>鼠标指针停留在二/三轨上按下e键 放置尾部时需要再次按下<code>e</code></td><td>无法重叠放置 且event尾部beat应该大于event头部beat</td></tr><tr><td>删除note/event</td><td>鼠标指针停留在note/事件上按下<code>d</code>键</td><td>无</td></tr><tr><td>选中note/event</td><td>左键单击选择</td><td>无</td></tr><tr><td>往复制表里添加/删除该note/event</td><td>右键单击选择/删除</td><td>无</td></tr><tr><td>修改note/event beat</td><td>选中note/event后按下<code>alt＋z</code>改变头部beat 类型为hold/event时可以按下<code>alt+x</code>改变尾部beat</td><td>无</td></tr><tr><td>裁剪event</td><td>选中event后按下<code>alt+c</code></td><td>裁剪后的event长度为当前beat细分的1/2</td></tr><tr><td>翻转event</td><td>选中event后按下<code>alt+b</code></td><td>起始值和终点值会镜像</td></tr><tr><td>event数值快速更改</td><td>选中event后在play区域按下<code>alt+t</code></td><td>如果鼠标指针的所在的beat小于event头的beat会将起始值更改为鼠标所在play位置的<code>x</code>值 否则会更改终点值</td></tr></tbody></table><h3 id="play区域" tabindex="-1">play区域 <a class="header-anchor" href="#play区域" aria-label="Permalink to &quot;play区域&quot;">​</a></h3><ul><li>点击play区域的轨道会将当前轨道切换到该轨道 如果多个轨道叠在一起 再次按下可以切换到下一个轨道</li><li>play区域无法编辑event 其余编辑方法与edit区域相同</li></ul><h3 id="批量操作" tabindex="-1">批量操作 <a class="header-anchor" href="#批量操作" aria-label="Permalink to &quot;批量操作&quot;">​</a></h3><h4 id="触发" tabindex="-1">触发 <a class="header-anchor" href="#触发" aria-label="Permalink to &quot;触发&quot;">​</a></h4><ul><li><p>按住左键会出现复制框 在左键松开之前按下shift会移除复制表中的所有内容 然后添加为现在框选的内容</p></li><li><p>如果并非按下<code>ctrl＋x</code> 被框选到的note/event会标记蓝色 按下<code>ctrl+x</code>后会标记成白色</p></li><li><p>右键单击note/event会将该其加入复制表</p></li></ul><p>以下操作均需要复制框有内容才会发生</p><table tabindex="0"><thead><tr><th>操作</th><th>方式</th><th>注意事项</th></tr></thead><tbody><tr><td>批量删除note/event</td><td><code>ctrl+d</code></td><td>无</td></tr><tr><td>复制</td><td><code>ctrl+c</code></td><td>无</td></tr><tr><td>裁剪</td><td><code>ctrl+x</code></td><td>裁剪后标记会变为白色</td></tr><tr><td>粘贴</td><td><code>ctrl+v</code></td><td>裁剪后的粘贴会删除掉裁剪的内容 如果选中的内容是在play中选中的 则粘贴后不粘贴event</td></tr><tr><td>粘贴 镜像x事件</td><td><code>ctrl+b</code></td><td>裁剪后的粘贴会删除掉裁剪的内容 如果选中的内容是在play中选中的 则粘贴后不粘贴event</td></tr><tr><td>粘贴</td><td><code>ctrl+a+v</code></td><td>裁剪后的粘贴会删除掉裁剪的内容 会粘贴play的event</td></tr><tr><td>粘贴 镜像x事件</td><td><code>ctrl+a+b</code></td><td>裁剪后的粘贴会删除掉裁剪的内容 会粘贴play的event</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>以下为已删除的快捷键</p><p>v0.5.0删除</p><table tabindex="0"><thead><tr><th>操作</th><th>方式</th><th>注意事项</th></tr></thead><tbody><tr><td>轨道快速创建</td><td><code>ctrl+n</code></td><td>会依据当前在鼠标所在play的x位置来更改粘贴后event的内容 并且会粘贴到一条新轨道上</td></tr><tr><td>轨道快速批量创建</td><td><code>ctrl+a+n</code></td><td>会依据当前在鼠标所在play的<code>x</code>位置来更改粘贴后event的内容 并且会粘贴多条新轨道上</td></tr><tr><td>同类型事件创建</td><td><code>ctrl+m</code></td><td>会依据当前在鼠标所在play的<code>x</code>位置来更改粘贴后event的内容 并且会粘贴到当前轨道上</td></tr><tr><td>批量同类型事件创建</td><td><code>ctrl+a+m</code></td><td>会依据当前在鼠标所在play的x位置来更改粘贴后event的内容 并且会粘贴到原来复制的轨道上</td></tr></tbody></table></div><h3 id="demo" tabindex="-1">demo <a class="header-anchor" href="#demo" aria-label="Permalink to &quot;demo&quot;">​</a></h3><p>演示模式 用于预览与录制谱面</p><ul><li>按下<code>tab</code>进入<code>demo_mode</code>,再次按下退出</li><li>期间只能使用<code>tab</code>和<code>space</code></li></ul><h2 id="侧边栏" tabindex="-1">侧边栏 <a class="header-anchor" href="#侧边栏" aria-label="Permalink to &quot;侧边栏&quot;">​</a></h2><h3 id="tracks-edit" tabindex="-1">tracks_edit <a class="header-anchor" href="#tracks-edit" aria-label="Permalink to &quot;tracks_edit&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>v0.5.0删除</p></div><ul><li><p>进入后会自动进入多轨编辑模式 按下<code>esc</code>键会退出 在侧边栏下有add和sub按钮 按下后会添加新的轨道或删除当前选中输入框的轨道</p></li><li><p>在多轨编辑模式中按下<code>left</code>/<code>right</code>会将当前所有轨道向左/右平移</p></li></ul><h3 id="multiple-events-edit" tabindex="-1">multiple_events_edit <a class="header-anchor" href="#multiple-events-edit" aria-label="Permalink to &quot;multiple_events_edit&quot;">​</a></h3><ul><li><p>触发：选中到event</p></li><li><p>扰动会使event的数字增加/减少在-扰动值到+扰动值范围内的随机数</p></li><li><p>从（from）到（to）会赋予选中事件的初始值到结束值的数（数值大小遵循trans）</p></li><li><p>trans 是form to的过渡</p></li><li><p>trans 有三种类型bezier easing function</p></li><li><p>type 为bezier时 string应为bezier的点坐标 第奇数个数字代表这个点的x坐标 第偶数个数字代表这个点的y坐标</p></li></ul><p>例如</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        bezier 0,0,1,1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        bezier 0,0,0.5,1,2,2</span></span></code></pre></div><ul><li>type 为easing时 string应为数字或是easing的名称 其中当string为easing的名称时 因全部字母小写且每个单词用_隔开</li></ul><p>例如</p><pre><code>     easing 1 

     easing in_circ 
</code></pre><ul><li>type 为function时 string应该为function表达式 函数的传入值为 x 其中x大于等于0 x小于等于1 比如sin这样的函数调用时应该遵循lua的语法</li></ul><p>例如</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>          function 1/x </span></span>
<span class="line"><span>          function math.cos(x)</span></span></code></pre></div><h3 id="preference" tabindex="-1">preference <a class="header-anchor" href="#preference" aria-label="Permalink to &quot;preference&quot;">​</a></h3><ul><li>偏好：允许根据个人编辑习惯调整编辑模式 目前支持调整event缩放与偏移</li></ul><h2 id="effect" tabindex="-1">effect <a class="header-anchor" href="#effect" aria-label="Permalink to &quot;effect&quot;">​</a></h2><ul><li>目前effect不支持在制谱器内编辑 且只能在演示模式下预览</li></ul><h3 id="effect编辑" tabindex="-1">effect编辑 <a class="header-anchor" href="#effect编辑" aria-label="Permalink to &quot;effect编辑&quot;">​</a></h3><ul><li>请前往谱面保存目录中找到谱面并打开（后缀为json）然后找到effect这项属性</li></ul><h4 id="v0-5-0以上" tabindex="-1">v0.5.0以上： <a class="header-anchor" href="#v0-5-0以上" aria-label="Permalink to &quot;v0.5.0以上：&quot;">​</a></h4><ul><li>effect写法与event类似 须有trans，beat,beat2,type,from,to这几项属性 请参考开发文档中的event结构</li></ul><h4 id="v0-5-0以下" tabindex="-1">v0.5.0以下： <a class="header-anchor" href="#v0-5-0以下" aria-label="Permalink to &quot;v0.5.0以下：&quot;">​</a></h4><ul><li>参照写法：</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>effect = {</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>        trans={0,0,1,1},</span></span>
<span class="line"><span>        beat2={0,1,4},</span></span>
<span class="line"><span>        type=&#39;note_alpha&#39;,</span></span>
<span class="line"><span>        beat={0,0,1},</span></span>
<span class="line"><span>        from=100,</span></span>
<span class="line"><span>        to=12.5</span></span>
<span class="line"><span>},</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>        trans={0,1,1,1},</span></span>
<span class="line"><span>        beat2={4,1,4},</span></span>
<span class="line"><span>        type=&#39;note_rotate&#39;,</span></span>
<span class="line"><span>        beat={3,0,1},</span></span>
<span class="line"><span>        from=100,</span></span>
<span class="line"><span>        to=12.5</span></span>
<span class="line"><span>},</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><ul><li>其中 每一项应该按照beat从小到大来排列</li></ul></div><ul><li>type类型有</li></ul><p>|类型|范围| |note_alpha|0-100| |track_alpha|0-100| |track_line_alpha|0-100| |note_rotate|0-2pi|</p><ul><li>如果数值超了范围（除了note_rotate） 超了范围的部分不会显示出来 （比如 note_alpha 值为110 只会显示为100时候的效果）</li></ul><h2 id="自定义" tabindex="-1">自定义 <a class="header-anchor" href="#自定义" aria-label="Permalink to &quot;自定义&quot;">​</a></h2><h3 id="v0-5-0以上-1" tabindex="-1">v0.5.0以上： <a class="header-anchor" href="#v0-5-0以上-1" aria-label="Permalink to &quot;v0.5.0以上：&quot;">​</a></h3><h4 id="打击音" tabindex="-1">打击音 <a class="header-anchor" href="#打击音" aria-label="Permalink to &quot;打击音&quot;">​</a></h4><ul><li>请将打击音的前缀改为<code>hit</code> 然后放入<code>users</code>文件夹中</li></ul><h4 id="note" tabindex="-1">note <a class="header-anchor" href="#note" aria-label="Permalink to &quot;note&quot;">​</a></h4><table tabindex="0"><thead><tr><th>note类型</th><th>图片名称</th></tr></thead><tbody><tr><td>note</td><td>note.png</td></tr><tr><td>hold头</td><td>holdHead.png</td></tr><tr><td>hold身</td><td>holdBody.png</td></tr><tr><td>hold尾</td><td>holdTail.png</td></tr><tr><td>wipe</td><td>wipe.png</td></tr></tbody></table><h4 id="键位" tabindex="-1">键位 <a class="header-anchor" href="#键位" aria-label="Permalink to &quot;键位&quot;">​</a></h4><ul><li>修改key.lua（在dakumi.exe同一目录）</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>若是导致dakumi功能异常请重新下载一份key.lua</p></div><h4 id="默认bezier表" tabindex="-1">默认bezier表 <a class="header-anchor" href="#默认bezier表" aria-label="Permalink to &quot;默认bezier表&quot;">​</a></h4><ul><li>修改defaultBezier.txt（在dakumi.exe同一目录）</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>若是导致dakumi功能异常请重新下载一份defaultBezier.txt</p></div><h3 id="v0-5-0以下-1" tabindex="-1">v0.5.0以下： <a class="header-anchor" href="#v0-5-0以下-1" aria-label="Permalink to &quot;v0.5.0以下：&quot;">​</a></h3><ul><li><p>打击音 请将打击音的前缀改为<code>hit_sound</code> 然后拖入到dakumi的窗口中</p></li><li><p>note皮肤 请将图片素材的前缀改成以下的名称并通过<code>目录</code>打开dakumi的ui文件夹后导入 所使用的图片大小最好相同</p></li></ul>`,72)]))}const b=e(o,[["render",n]]);export{u as __pageData,b as default};
